            //       add {start[i], end[i]} to selected, update lastEnd = end[i]
        }
        return selected;
    }

    public static void main(String[] args) {
        ActivitySelection as = new ActivitySelection();
        int[] s = {1, 3, 0, 5, 8, 5};
        int[] e = {2, 4, 6, 7, 9, 9};
        List<int[]> result = as.selectActivities(s, e);
        System.out.println("Selected " + result.size() + " activities:");
        for (int[] a : result)
