}

import java.util.*;

public class MeetingRooms {

    public int minRooms(int[][] intervals) {
        if (intervals.length == 0) return 0;
        // Sort by start time
        Arrays.sort(intervals, (a, b) -> a[0] - b[0]);
        // Min-heap of end times
        PriorityQueue<Integer> endTimes = new PriorityQueue<>();
        endTimes.add(intervals[0][1]);

        for (int i = 1; i < intervals.length; i++) {
            // TODO: if the earliest-ending room is free (its end <= current start),
            //       reuse it by polling from endTimes; else a new room is needed
            //       then add current interval's end time to endTimes
        }
        return endTimes.size();
    }

    public static void main(String[] args) {
        MeetingRooms mr = new MeetingRooms();
        int[][] m1 = {{0,30},{5,10},{15,20}};
        System.out.println("[[0,30],[5,10],[15,20]]: " + mr.minRooms(m1) + " rooms");

        int[][] m2 = {{7,10},{2,4}};
        System.out.println("[[7,10],[2,4]]: " + mr.minRooms(m2) + " rooms");

        int[][] m3 = {{1,4},{2,5},{3,6}};
        System.out.println("[[1,4],[2,5],[3,6]]: " + mr.minRooms(m3) + " rooms");
    }
}

import java.util.Arrays;

public class NonOverlapIntervals {

    public int minRemovals(int[][] intervals) {
        if (intervals.length == 0) return 0;
        // Sort by end time
        Arrays.sort(intervals, (a, b) -> a[1] - b[1]);

        int kept = 1;
        int lastEnd = intervals[0][1];

        for (int i = 1; i < intervals.length; i++) {
            // TODO: if intervals[i][0] >= lastEnd, keep this interval
            //       increment kept and update lastEnd = intervals[i][1]
        }
        return intervals.length - kept;
    }

    public static void main(String[] args) {
        NonOverlapIntervals noi = new NonOverlapIntervals();
        System.out.println("[[1,2],[2,3],[3,4],[1,3]]: " + noi.minRemovals(new int[][]{{1,2},{2,3},{3,4},{1,3}}));
        System.out.println("[[1,2],[1,2],[1,2]]:        " + noi.minRemovals(new int[][]{{1,2},{1,2},{1,2}}));
        System.out.println("[[1,2],[2,3]]:               " + noi.minRemovals(new int[][]{{1,2},{2,3}}));
    }
}
